insert into public.courses (id,title,slug,excerpt,description,duration,requirements,learning_outcomes,who_should_attend,benefits,faqs,category_id,featured_image,og_image,is_featured,seo_title,seo_description) values
('20000000-0000-0000-0000-000000000001','Computer Literacy','computer-literacy','A practical introduction to computers, the internet, email and essential office applications.','This foundational programme helps learners become confident computer users. Training is practical, instructor-led and suitable for beginners who want workplace-ready digital skills.','5 days','["No previous computer experience required","Basic English literacy"]','["Use a computer confidently","Create and manage files and folders","Use email and the internet responsibly","Complete basic tasks in common office applications"]','["First-time computer users","Job seekers","Employees needing digital confidence"]','["Practical exercises","Supportive classroom environment","Skills applicable to daily office work"]','[{"question":"Is this suitable for complete beginners?","answer":"Yes. The programme starts with the basics and builds confidence through guided practice."},{"question":"Will I use a computer during the training?","answer":"Yes. The course is designed around practical exercises."}]','10000000-0000-0000-0000-000000000001','/images/course-computer-literacy.svg','/images/course-computer-literacy.svg',true,'Computer Literacy Course in Port Elizabeth | New Era','Learn essential computer skills with practical beginner-friendly training in Port Elizabeth (Gqeberha).'),
('20000000-0000-0000-0000-000000000002','Intermediate Computer Skills','intermediate-computer-skills','Strengthen your office productivity, document management and everyday digital workflow.','Designed for learners who already understand the basics and want to improve efficiency, accuracy and confidence when working with office software and digital information.','5 days','["Basic computer literacy"]','["Improve document formatting","Manage files more efficiently","Use spreadsheets for routine workplace tasks","Apply better digital work habits"]','["Office workers","Administrative staff","Learners progressing beyond beginner level"]','["Workplace-focused practice","Improved productivity","Structured skill progression"]','[{"question":"Do I need to complete the beginner course first?","answer":"Not necessarily. Learners with basic computer skills may enrol directly."}]','10000000-0000-0000-0000-000000000001','/images/course-intermediate.svg','/images/course-intermediate.svg',true,'Intermediate Computer Skills Course | New Era Gqeberha','Improve office productivity with intermediate computer skills training in Port Elizabeth.'),
('20000000-0000-0000-0000-000000000003','Advanced Computer Skills','advanced-computer-skills','Develop advanced office application skills for more demanding workplace responsibilities.','An advanced programme for learners seeking stronger productivity, reporting and digital workflow skills for the workplace.','5 days','["Intermediate computer skills"]','["Handle more complex office tasks","Use productivity tools efficiently","Prepare professional documents and reports","Apply advanced digital workflow practices"]','["Experienced office workers","Supervisors","Administrative professionals"]','["Advanced practical exercises","Professional workflow improvement","Career-relevant skills"]','[{"question":"Who is this course for?","answer":"It is aimed at learners who already work confidently with computers and want to progress further."}]','10000000-0000-0000-0000-000000000001','/images/course-advanced.svg','/images/course-advanced.svg',true,'Advanced Computer Skills Course in Gqeberha | New Era','Build advanced workplace computer skills with professional training in Port Elizabeth.'),
('20000000-0000-0000-0000-000000000004','Microsoft Word','microsoft-word','Create, format and manage professional documents using Microsoft Word.','Learn the practical Microsoft Word skills needed to produce polished workplace documents, letters and reports.','2 days','["Basic computer literacy"]','["Format professional documents","Use tables and page layouts","Prepare letters and reports","Work efficiently with Word tools"]','["Office workers","Students","Administrative staff"]','["Hands-on document practice","Improved office readiness","Better document presentation"]','[]','10000000-0000-0000-0000-000000000002','/images/course-word.svg','/images/course-word.svg',false,'Microsoft Word Training in Port Elizabeth | New Era','Learn practical Microsoft Word skills for professional documents and reports.'),
('20000000-0000-0000-0000-000000000005','Microsoft Excel','microsoft-excel','Build practical spreadsheet skills for calculations, data organisation and reporting.','Learn how to use Microsoft Excel for everyday workplace calculations, lists, basic analysis and reporting.','3 days','["Basic computer literacy"]','["Create and format spreadsheets","Use common formulas","Organise workplace data","Prepare clear basic reports"]','["Administrative staff","Small business teams","Office workers"]','["Practical spreadsheet exercises","Workplace-ready formulas","Improved data confidence"]','[{"question":"Does the course include formulas?","answer":"Yes. Learners practise commonly used formulas and everyday spreadsheet tasks."}]','10000000-0000-0000-0000-000000000002','/images/course-excel.svg','/images/course-excel.svg',true,'Microsoft Excel Course in Port Elizabeth | New Era','Learn practical Microsoft Excel spreadsheet skills for the workplace in Gqeberha.'),
('20000000-0000-0000-0000-000000000006','Microsoft PowerPoint','microsoft-powerpoint','Create professional presentations with clear structure and effective visual communication.','This practical course teaches learners how to create, format and present effective slides for meetings and training sessions.','1 day','["Basic computer literacy"]','["Build structured slide decks","Use layouts and themes","Add images and simple charts","Present information clearly"]','["Employees","Students","Team leaders"]','["Presentation confidence","Better visual communication","Practical slide creation"]','[]','10000000-0000-0000-0000-000000000002','/images/course-powerpoint.svg','/images/course-powerpoint.svg',false,'Microsoft PowerPoint Training | New Era Port Elizabeth','Create professional presentations with practical Microsoft PowerPoint training.'),
('20000000-0000-0000-0000-000000000007','IT End User Computing','it-end-user-computing','Develop structured end-user computing skills for study, work and professional development.','A structured programme covering the practical digital knowledge and application skills needed by modern computer users.','Contact us for programme options','["Programme entry requirements are confirmed during enquiry"]','["Apply end-user computing principles","Use digital tools productively","Work with office applications","Strengthen workplace readiness"]','["Job seekers","Employees","Organisations seeking structured training"]','["Structured learning pathway","Practical digital skills","Suitable for group delivery"]','[]','10000000-0000-0000-0000-000000000001','/images/course-end-user.svg','/images/course-end-user.svg',false,'IT End User Computing Training in Gqeberha | New Era','Structured IT end user computing skills development for individuals and organisations.'),
('20000000-0000-0000-0000-000000000008','Project Management','project-management','Understand the practical principles of planning, organising and monitoring projects.','Develop practical project management awareness for better planning, communication and delivery in the workplace.','3 days','["No specialist software knowledge required"]','["Understand project stages","Set goals and milestones","Monitor tasks and responsibilities","Improve project communication"]','["Team leaders","Administrators","Employees supporting projects"]','["Practical planning methods","Clearer project communication","Improved organisation"]','[]','10000000-0000-0000-0000-000000000003','/images/course-project.svg','/images/course-project.svg',true,'Project Management Course in Port Elizabeth | New Era','Learn practical project planning and management skills for the workplace.'),
('20000000-0000-0000-0000-000000000009','Records Management','records-management','Improve the organisation, handling and retrieval of workplace records.','This programme introduces practical methods for managing records accurately and consistently in office environments.','2 days','["Suitable for administrative and support staff"]','["Organise records systematically","Improve retrieval processes","Understand record handling responsibilities","Apply practical office procedures"]','["Administrative staff","Records officers","Office support teams"]','["Better organisation","Improved information retrieval","Practical office procedures"]','[]','10000000-0000-0000-0000-000000000003','/images/course-records.svg','/images/course-records.svg',false,'Records Management Training | New Era Gqeberha','Improve workplace records organisation and retrieval with practical training.')
