insert into public.blog_posts (id,title,slug,excerpt,content,featured_image,og_image,seo_title,seo_description,status,tags,category_id,created_at) values
('40000000-0000-0000-0000-000000000001','Why Computer Literacy Still Matters in the Modern Workplace','why-computer-literacy-still-matters','Digital confidence remains essential for job seekers, employees and anyone building workplace skills.','Computer literacy is more than knowing how to switch on a computer. In the workplace, it includes managing files, communicating by email, using office applications and working confidently with digital information. A structured beginner programme can help learners develop these skills through practical exercises and guided support.
